import React, { useState, useEffect } from 'react';
import { useAuth } from '../../contexts/AuthContext';
import { profileAPI, mentorsAPI, quizAPI } from '../../services/api';
import './Progress.css';

const Progress = () => {
  const [progress, setProgress] = useState({
    quizCompleted: 0,
    profileCompleted: 0,
    skillsAdded: 0,
    mentorsConnected: 0,
    coursesEnrolled: 0
  });
  const [loading, setLoading] = useState(true);
  const [lastUpdated, setLastUpdated] = useState(null);
  const { user } = useAuth();

  // Real-time progress tracking
  useEffect(() => {
    fetchProgress();
    
    // Set up interval to refresh progress every 30 seconds
    const interval = setInterval(fetchProgress, 30000);
    
    return () => clearInterval(interval);
  }, [user]);

  const fetchProgress = async () => {
    try {
      console.log('🔄 Fetching progress data...');
      
      const [
        profileResponse, 
        mentorResponse, 
        quizResponse
      ] = await Promise.allSettled([
        profileAPI.getProfile(),
        mentorsAPI.getMyRequests(),
        quizAPI.getHistory()
      ]);

      console.log('📊 API Responses:', {
        profile: profileResponse,
        mentor: mentorResponse,
        quiz: quizResponse
      });

      // Calculate quiz completion
      let quizCompleted = 0;
      if (quizResponse.status === 'fulfilled' && quizResponse.value.success) {
        quizCompleted = quizResponse.value.history?.length > 0 ? 100 : 0;
      } else {
        quizCompleted = (user?.quizResults?.length > 0) ? 100 : 0;
      }

      // Calculate profile completion
      let profileCompleted = 0;
      let skillsAdded = 0;
      if (profileResponse.status === 'fulfilled' && profileResponse.value.user) {
        const userProfile = profileResponse.value.user.profile || {};
        profileCompleted = calculateProfileCompletion(userProfile);
        skillsAdded = calculateSkillsProgress(userProfile.skills || []);
      } else {
        profileCompleted = calculateProfileCompletion(user?.profile || {});
        skillsAdded = calculateSkillsProgress(user?.profile?.skills || []);
      }

      // Calculate mentor connections
      let mentorsConnected = 0;
      if (mentorResponse.status === 'fulfilled' && mentorResponse.value.success) {
        const acceptedMentors = mentorResponse.value.requests?.filter(
          req => req.status === 'accepted'
        ).length || 0;
        mentorsConnected = Math.min((acceptedMentors / 3) * 100, 100);
      }

      const progressData = {
        quizCompleted,
        profileCompleted,
        skillsAdded,
        mentorsConnected,
        coursesEnrolled: calculateCourseProgress() // You can implement this later
      };
      
      console.log('🎯 Final Progress Data:', progressData);
      setProgress(progressData);
      setLastUpdated(new Date());
      
    } catch (error) {
      console.error('❌ Error in fetchProgress:', error);
      // Fallback calculation
      const fallbackProgress = calculateProgressFromUser(user);
      setProgress(fallbackProgress);
    } finally {
      setLoading(false);
    }
  };

  const calculateProgressFromUser = (userData) => {
    const quizCompleted = (userData?.quizResults?.length > 0) ? 100 : 0;
    const profileCompleted = calculateProfileCompletion(userData?.profile || {});
    const skillsAdded = calculateSkillsProgress(userData?.profile?.skills || []);
    
    return {
      quizCompleted,
      profileCompleted,
      skillsAdded,
      mentorsConnected: 0,
      coursesEnrolled: 0
    };
  };

  const calculateProfileCompletion = (profile) => {
    if (!profile) return 0;
    
    const completionCriteria = [
      { key: 'bio', weight: 20, check: (val) => val && val.trim().length > 10 },
      { key: 'education', weight: 20, check: (val) => val && val.trim().length > 0 },
      { key: 'experience', weight: 20, check: (val) => val !== undefined && val !== null },
      { key: 'skills', weight: 20, check: (val) => val && val.length > 0 },
      { key: 'interests', weight: 20, check: (val) => val && val.length > 0 }
    ];

    let totalScore = 0;
    completionCriteria.forEach(criteria => {
      if (criteria.check(profile[criteria.key])) {
        totalScore += criteria.weight;
        console.log(`✅ ${criteria.key}: +${criteria.weight}%`);
      }
    });

    console.log(`📊 Profile completion score: ${totalScore}%`);
    return totalScore;
  };

  const calculateSkillsProgress = (skills) => {
    const skillsCount = skills.length;
    const progress = Math.min((skillsCount / 5) * 100, 100);
    console.log(`🛠️ Skills progress: ${skillsCount}/5 skills = ${progress}%`);
    return progress;
  };

  const calculateCourseProgress = () => {
    // Mock data - implement with your courses API
    // You can track: enrolled courses, completed courses, etc.
    return Math.floor(Math.random() * 30); // Random progress for demo
  };

  const getOverallProgress = () => {
    const values = Object.values(progress);
    const overall = Math.round(values.reduce((a, b) => a + b, 0) / values.length);
    return overall;
  };

  const getProgressColor = (percentage) => {
    if (percentage >= 80) return '#10b981'; // Green
    if (percentage >= 50) return '#f59e0b'; // Yellow
    return '#ef4444'; // Red
  };

  const getProgressLevel = () => {
    const overall = getOverallProgress();
    if (overall >= 80) return { text: 'Advanced', emoji: '🚀' };
    if (overall >= 60) return { text: 'Intermediate', emoji: '⭐' };
    if (overall >= 40) return { text: 'Beginner', emoji: '🌱' };
    return { text: 'Getting Started', emoji: '🎯' };
  };

  const refreshProgress = () => {
    setLoading(true);
    fetchProgress();
  };

  const formatTime = (date) => {
    if (!date) return 'Never';
    return date.toLocaleTimeString();
  };

  if (!user) {
    return (
      <div className="progress-container">
        <div className="container">
          <div className="auth-required">
            <h2>Authentication Required</h2>
            <p>Please log in to view your progress.</p>
          </div>
        </div>
      </div>
    );
  }

  if (loading) {
    return (
      <div className="progress-container">
        <div className="container">
          <div className="loading">
            <div className="spinner"></div>
            Loading your progress...
          </div>
        </div>
      </div>
    );
  }

  const progressLevel = getProgressLevel();

  return (
    <div className="progress-container">
      <div className="container">
        <div className="progress-header">
          <div className="header-content">
            <div>
              <h1>📊 Your Career Progress</h1>
              <p>Track your career development journey</p>
            </div>
            <div className="header-actions">
              <button 
                onClick={refreshProgress}
                className="btn btn-secondary refresh-btn"
                disabled={loading}
              >
                {loading ? '🔄 Updating...' : '🔄 Refresh'}
              </button>
            </div>
          </div>
          {lastUpdated && (
            <div className="last-updated">
              Last updated: {formatTime(lastUpdated)}
            </div>
          )}
        </div>

        {/* Progress Level Badge */}
        <div className="progress-level-badge">
          <span className="level-emoji">{progressLevel.emoji}</span>
          <span className="level-text">{progressLevel.text} Level</span>
          <span className="level-percentage">{getOverallProgress()}% Overall</span>
        </div>

        {/* Overall Progress */}
        <div className="overall-progress-section">
          <div className="progress-card">
            <div className="progress-card-header">
              <h2>Overall Career Progress</h2>
              <div className="progress-stats">
                <div className="stat">
                  <span className="stat-value">{Math.round(progress.quizCompleted)}%</span>
                  <span className="stat-label">Assessment</span>
                </div>
                <div className="stat">
                  <span className="stat-value">{Math.round(progress.profileCompleted)}%</span>
                  <span className="stat-label">Profile</span>
                </div>
                <div className="stat">
                  <span className="stat-value">{Math.round(progress.mentorsConnected)}%</span>
                  <span className="stat-label">Mentors</span>
                </div>
              </div>
            </div>
            
            <div className="progress-circle-large">
              <div 
                className="circle" 
                style={{ 
                  background: `conic-gradient(${getProgressColor(getOverallProgress())} ${getOverallProgress() * 3.6}deg, #e2e8f0 0deg)` 
                }}
              >
                <span className="progress-value">{getOverallProgress()}%</span>
              </div>
            </div>
            
            <div className="progress-milestones">
              <div className={`milestone ${getOverallProgress() >= 25 ? 'completed' : ''}`}>
                <span className="milestone-number">1</span>
                <span className="milestone-text">Career Assessment</span>
              </div>
              <div className={`milestone ${getOverallProgress() >= 50 ? 'completed' : ''}`}>
                <span className="milestone-number">2</span>
                <span className="milestone-text">Profile Setup</span>
              </div>
              <div className={`milestone ${getOverallProgress() >= 75 ? 'completed' : ''}`}>
                <span className="milestone-number">3</span>
                <span className="milestone-text">Mentor Connection</span>
              </div>
              <div className={`milestone ${getOverallProgress() >= 90 ? 'completed' : ''}`}>
                <span className="milestone-number">4</span>
                <span className="milestone-text">Skill Development</span>
              </div>
            </div>
          </div>
        </div>

        {/* Detailed Progress */}
        <div className="detailed-progress">
          <h3>Detailed Progress Breakdown</h3>
          
          <div className="progress-grid">
            <div className="progress-category">
              <div className="category-header">
                <h4>Career Assessment</h4>
                <span className="category-percentage">{Math.round(progress.quizCompleted)}%</span>
              </div>
              <div className="progress-bar">
                <div 
                  className="progress-fill" 
                  style={{ 
                    width: `${progress.quizCompleted}%`,
                    backgroundColor: getProgressColor(progress.quizCompleted)
                  }}
                ></div>
              </div>
              <div className="category-actions">
                {progress.quizCompleted === 100 ? (
                  <span className="completed-text">✅ Assessment Complete</span>
                ) : (
                  <button 
                    onClick={() => window.location.href = '/quiz'}
                    className="btn btn-primary btn-small"
                  >
                    Take Career Quiz
                  </button>
                )}
              </div>
            </div>

            <div className="progress-category">
              <div className="category-header">
                <h4>Profile Completion</h4>
                <span className="category-percentage">{Math.round(progress.profileCompleted)}%</span>
              </div>
              <div className="progress-bar">
                <div 
                  className="progress-fill" 
                  style={{ 
                    width: `${progress.profileCompleted}%`,
                    backgroundColor: getProgressColor(progress.profileCompleted)
                  }}
                ></div>
              </div>
              <div className="category-details">
                <span>Bio: {user?.profile?.bio ? '✅' : '❌'}</span>
                <span>Education: {user?.profile?.education ? '✅' : '❌'}</span>
                <span>Experience: {user?.profile?.experience !== undefined ? '✅' : '❌'}</span>
              </div>
              <div className="category-actions">
                {progress.profileCompleted < 100 && (
                  <button 
                    onClick={() => window.location.href = '/profile'}
                    className="btn btn-secondary btn-small"
                  >
                    Complete Profile
                  </button>
                )}
              </div>
            </div>

            <div className="progress-category">
              <div className="category-header">
                <h4>Mentor Connections</h4>
                <span className="category-percentage">{Math.round(progress.mentorsConnected)}%</span>
              </div>
              <div className="progress-bar">
                <div 
                  className="progress-fill" 
                  style={{ 
                    width: `${progress.mentorsConnected}%`,
                    backgroundColor: getProgressColor(progress.mentorsConnected)
                  }}
                ></div>
              </div>
              <div className="category-actions">
                <button 
                  onClick={() => window.location.href = '/mentors'}
                  className="btn btn-primary btn-small"
                >
                  {progress.mentorsConnected > 0 ? 'Find More Mentors' : 'Connect with Mentors'}
                </button>
              </div>
            </div>

            <div className="progress-category">
              <div className="category-header">
                <h4>Skills Development</h4>
                <span className="category-percentage">{Math.round(progress.skillsAdded)}%</span>
              </div>
              <div className="progress-bar">
                <div 
                  className="progress-fill" 
                  style={{ 
                    width: `${progress.skillsAdded}%`,
                    backgroundColor: getProgressColor(progress.skillsAdded)
                  }}
                ></div>
              </div>
              <div className="category-details">
                <span>Skills: {user?.profile?.skills?.length || 0}/5</span>
                <span>Interests: {user?.profile?.interests?.length || 0}</span>
              </div>
              <div className="category-actions">
                <button 
                  onClick={() => window.location.href = '/profile'}
                  className="btn btn-secondary btn-small"
                >
                  Manage Skills
                </button>
              </div>
            </div>

            <div className="progress-category">
              <div className="category-header">
                <h4>Learning Progress</h4>
                <span className="category-percentage">{Math.round(progress.coursesEnrolled)}%</span>
              </div>
              <div className="progress-bar">
                <div 
                  className="progress-fill" 
                  style={{ 
                    width: `${progress.coursesEnrolled}%`,
                    backgroundColor: getProgressColor(progress.coursesEnrolled)
                  }}
                ></div>
              </div>
              <div className="category-actions">
                <button 
                  onClick={() => window.location.href = '/courses'}
                  className="btn btn-primary btn-small"
                >
                  Explore Courses
                </button>
              </div>
            </div>
          </div>
        </div>

        {/* Progress Tips */}
        <div className="progress-tips">
          <h3>💡 Tips to Improve Your Progress</h3>
          <div className="tips-grid">
            {progress.quizCompleted === 0 && (
              <div className="tip-card">
                <h4>Take Career Assessment</h4>
                <p>Complete the career quiz to discover your ideal career path and get personalized recommendations.</p>
              </div>
            )}
            {progress.profileCompleted < 100 && (
              <div className="tip-card">
                <h4>Complete Your Profile</h4>
                <p>A complete profile helps us provide better career matches and mentor recommendations.</p>
              </div>
            )}
            {progress.skillsAdded < 80 && (
              <div className="tip-card">
                <h4>Add More Skills</h4>
                <p>List at least 5 skills to get better matches with mentors and learning resources.</p>
              </div>
            )}
            {progress.mentorsConnected === 0 && (
              <div className="tip-card">
                <h4>Connect with Mentors</h4>
                <p>Find mentors in your desired field to get guidance and accelerate your career growth.</p>
              </div>
            )}
            {getOverallProgress() >= 70 && (
              <div className="tip-card">
                <h4>Great Progress! 🎉</h4>
                <p>You're doing well! Consider exploring advanced courses and networking with more mentors.</p>
              </div>
            )}
          </div>
        </div>
      </div>
    </div>
  );
};

export default Progress;
